package com.hospital.management.controller.admission;import com.hospital.management.model.*;import com.hospital.management.util.RequestUtil;import javax.servlet.http.*;import java.time.*;final class AdmissionRequest{private AdmissionRequest(){}static Long id(String s){try{long x=Long.parseLong(s);return x>0?x:null;}catch(Exception e){return null;}}static int number(String s,int d){try{return Integer.parseInt(s);}catch(Exception e){return d;}}static LocalDate date(String s){try{return s==null||s.isBlank()?null:LocalDate.parse(s);}catch(Exception e){return null;}}static AuthenticatedUser user(HttpServletRequest q){HttpSession s=q.getSession(false);Object u=s==null?null:s.getAttribute("authenticatedUser");return u instanceof AuthenticatedUser a?a:null;}static AuditContext audit(HttpServletRequest q){return RequestUtil.buildAuditContext(q);}static AdmissionForm admission(HttpServletRequest q){AdmissionForm f=new AdmissionForm();f.setAdmissionId(id(q.getParameter("admissionId")));f.setPatientId(id(q.getParameter("patientId")));f.setDoctorId(id(q.getParameter("doctorId")));f.setDepartmentId(id(q.getParameter("departmentId")));f.setAppointmentId(id(q.getParameter("appointmentId")));f.setBedId(id(q.getParameter("bedId")));f.setExpectedDischargeDate(q.getParameter("expectedDischargeDate"));f.setAdmissionReason(q.getParameter("admissionReason"));return f;}}
